<?php $key=$user['run_key']?:bin2hex(random_bytes(16));$scheme=(!empty($_SERVER['HTTPS'])&&$_SERVER['HTTPS']!=='off')?'https':'http';$runUrl=$scheme.'://'.($_SERVER['HTTP_HOST']??'').dirname($_SERVER['SCRIPT_NAME']).'/index.php?r=step_run&key='.urlencode($user['run_key']?:$key);?><div class="card"><form method="post"><label>Zepp Life/小米运动账号</label><input name="zepp_username" value="<?=h($user['zepp_username']??'')?>" placeholder="手机号/邮箱"><label>Zepp Life/小米运动密码</label><input name="zepp_password" type="password" value="<?=h($user['zepp_password']??'')?>"><div class="step-range-grid"><div><label>最小步数</label><input name="step_min" type="number" value="<?=h($user['step_min']??3000)?>"></div><div><label>最大步数</label><input name="step_max" type="number" value="<?=h($user['step_max']??8000)?>"></div><div><label>执行时间</label><input name="run_time" type="time" value="<?=h($user['run_time']??'07:30')?>"></div></div><label style="display:flex;align-items:center;gap:10px"><input style="width:auto;min-height:auto" type="checkbox" name="auto_run" value="1" <?=!empty($user['auto_run'])?'checked':''?>> 定时执行</label><label>运行密钥</label><input name="run_key" value="<?=h($user['run_key']?:$key)?>"><p class="step-action-row"><button class="btn">保存配置</button><a class="btn green" href="index.php?r=step_test" data-step-run-confirm="1">立即执行</a></p></form></div><div class="card" id="submit-logs"><?php $lp=$logPage??['items'=>[],'page'=>1,'pages'=>1,'total'=>0,'perPage'=>5];$logs=$lp['items']??[]; ?><?php if(empty($logs)): ?><p class="muted">暂无提交日志。</p><?php else: ?><div class="table-wrap"><table><tr><th>时间</th><th>状态</th><th>步数</th><th>结果</th></tr><?php foreach($logs as $log): ?><tr><td><?=h($log['created_at'])?></td><td><span class="badge <?=$log['status']==='success'?'ok':'bad'?>"><?=h($log['status']==='success'?'成功':'失败')?></span></td><td><?=h($log['steps']!==null&&$log['steps']!==''?$log['steps']:'-')?></td><td><?=h($log['message'])?></td></tr><?php endforeach; ?></table></div><div class="pager"><span>第 <?=h($lp['page'])?> / <?=h($lp['pages'])?> 页，共 <?=h($lp['total'])?> 条</span><div class="pager-actions"><?php if($lp['page']>1): ?><a class="btn light" href="index.php?r=step_settings&log_page=<?=h($lp['page']-1)?>#submit-logs">上一页</a><?php else: ?><span class="btn light disabled">上一页</span><?php endif; ?><?php if($lp['page']<$lp['pages']): ?><a class="btn light" href="index.php?r=step_settings&log_page=<?=h($lp['page']+1)?>#submit-logs">下一页</a><?php else: ?><span class="btn light disabled">下一页</span><?php endif; ?></div></div><?php endif; ?></div><div class="card"><h3>执行说明</h3><p class="muted">点击“立即执行”会马上运行一次；开启自动定时后，系统每天到达设定时间会自动执行一次。同一天自动任务不会重复执行，但手动立即执行不受限制。</p><p>当前状态：<?=!empty($user['auto_run'])?'<span class="badge ok">已开启</span>':'<span class="badge bad">未开启</span>'?>　执行时间：<b><?=h($user['run_time']??'07:30')?></b>　上次自动执行日期：<b><?=h($user['last_step_run_date']?:'暂无')?></b></p><p class="muted">运行接口</p><div class="url" style="word-break:break-all;background:#f2f6ff;border-radius:14px;padding:14px"><?=h($runUrl)?></div></div><div class="step-modal-mask" id="step-run-modal" aria-hidden="true"><div class="step-modal-card" role="dialog" aria-modal="true" aria-labelledby="step-run-title"><div class="step-modal-icon">🏃</div><h3 id="step-run-title">立即执行步数任务？</h3><p class="muted">系统会马上使用当前保存的 Zepp Life / 小米运动账号提交一次随机步数。手动执行不受每日定时限制。</p><div class="step-modal-actions"><button type="button" class="btn light" data-step-modal-cancel>取消</button><a class="btn green" href="index.php?r=step_test" data-step-modal-ok>开始执行</a></div></div></div>